const pageContent = $input.first().json.data || '';
const webhookData = $('Webhook').first().json.body || {};
const tipo = webhookData.tipo || 'servicio';
const url  = webhookData.url  || '';

const tipoLabel = {
  viajes:       'Agencia de Viajes',
  medico:       'Médico / Clínica',
  abogado:      'Abogado / Bufete',
  inmobiliaria: 'Inmobiliaria',
  automotriz:   'Automotriz',
  producto:     'Tienda / Productos',
  servicio:     'Servicios / Agencia',
}[tipo] || 'Negocio';

const hasContent = typeof pageContent === 'string' && pageContent.trim().length > 200;

let prompt;

if (hasContent) {
  const trimmed = pageContent.slice(0, 6000);
  prompt = `Eres un experto en marketing digital y copywriting para negocios en Ecuador y Latinoamérica. Analizaste el siguiente contenido extraído de la web "${url}".

