  "heroTitle": "Título principal del hero, impactante y directo (máx 10 palabras)",
  "heroSub": "Subtítulo persuasivo de 1-2 oraciones",
  "heroCta": "Texto del botón principal (ej: Agendar Cita, Cotizar Ahora, Contactar)",
  "servs": [
